        data: {"result": {"minY": 29.0, "minX": 0.0, "maxY": 2000.0, "series": [{"data": [[0.0, 2000.0]], "isOverall": false, "label": "DELETE Character", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "POST Character", "isController": false}, {"data": [[0.0, 1164.0], [300.0, 79.0], [100.0, 290.0], [200.0, 308.0], [400.0, 130.0], [500.0, 29.0]], "isOverall": false, "label": "GET All Characters", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "GET Character by ID", "isController": false}, {"data": [[0.0, 2000.0]], "isOverall": false, "label": "PUT Character", "isController": false}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 500.0, "title": "Response Time Distribution"}},
